    PyArrayObject *w = (PyArrayObject*)PyArray_FROM_OTF((PyObject*)weights_array, NPY_DOUBLE, NPY_ARRAY_IN_ARRAY);
    PyArrayObject *cov = (PyArrayObject*)PyArray_FROM_OTF((PyObject*)cov_array, NPY_DOUBLE, NPY_ARRAY_IN_ARRAY);
