        double row_sum = 0.0;
        for (npy_intp j = 0; j < n; j++) {
            row_sum += row[j] * x[j];
        }
        risk_squared += x[i] * row_sum;
    }

    Py_DECREF(w);
    Py_DECREF(cov);

    return PyFloat_FromDouble(sqrt(risk_squared));
}

